const config = $('⚙️ Config').first().json;
if ((config.enableWeather || 'true').toLowerCase() !== 'true') {
  return [{ json: { weather: null } }];
}

const data = $input.first()?.json || {};
if (!data || data.error || Number(data.cod) !== 200 || !data.weather || !data.main) {
  return [{ json: { weather: null } }];
}

const emojiMap = {
  thunderstorm: '⛈',
  drizzle: '🌦',
  rain: '🌧',
  snow: '❄️',
  mist: '🌫',
  smoke: '🌫',
  haze: '🌫',
  dust: '🌫',
  fog: '🌫',
  sand: '🌫',
  ash: '🌫',
  squall: '🌬',
  tornado: '🌪',
  clear: '☀️',
  clouds: '⛅'
};

const main = String(data.weather?.[0]?.main || '').toLowerCase();
const description = String(data.weather?.[0]?.description || 'Weather unavailable');
const emoji = emojiMap[main] || '🌤';

const section = [
  '🌤 <b>Weather</b>',
  `${emoji} ${description} • ${Math.round(Number(data.main.temp))}°C (feels like ${Math.round(Number(data.main.feels_like))}°C)`,
  `↑ ${Math.round(Number(data.main.temp_max))}° ↓ ${Math.round(Number(data.main.temp_min))}°`
].join('\n');

return [{ json: { weather: section } }];

const config = $('⚙️ Config').first().json;

if ((config.enableTechNews || 'true').toLowerCase() !== 'true') {
  return [{ json: { techNews: null } }];
}

const ids = $input.all().map(item => item.json).filter(id => typeof id === 'number');

if (!ids.length) {
  return [{ json: { techNews: null } }];
}

const shortlist = ids.slice(0, 30);
const results = [];

for (let i = 0; i < shortlist.length; i += 10) {
  const batch = shortlist.slice(i, i + 10);

  const fetched = await Promise.all(
    batch.map(async (id) => {
      try {
        return await this.helpers.httpRequest({
          method: 'GET',
          url: `https://hacker-news.firebaseio.com/v0/item/${id}.json`,
          json: true,
        });
      } catch {
        return null;
      }
    })
  );

  results.push(...fetched.filter(Boolean));
}

const stories = results
  .filter(s => s && s.type === 'story' && s.url && Number(s.score || 0) > 50)
  .sort((a, b) => Number(b.score || 0) - Number(a.score || 0))
  .slice(0, 8);

if (!stories.length) {
  return [{ json: { techNews: '📰 <b>News Highlights</b>\n<i>No news found today</i>' } }];
}

const lines = ['📰 <b>News Highlights</b>'];

for (let i = 0; i < stories.length; i++) {
  const s = stories[i];
  lines.push(`${i + 1}. <b>${s.title}</b>`);
  lines.push(`   🔗 <a href="${s.url}">Read more</a>`);
  lines.push('');
}

return [{ json: { techNews: lines.join('\n').trim() } }];

const config = $('⚙️ Config').first().json;

if (
  (config.enableAINews || 'true').toLowerCase() !== 'true' ||
  (config.enableArxiv || 'true').toLowerCase() !== 'true'
) {
  return [{ json: { arxiv: null } }];
}

const item = $input.first();
const text =
  typeof item.json === 'string'
    ? item.json
    : JSON.stringify(item.json || {});

const clean = (value) => String(value || '').replace(/\s+/g, ' ').trim();

const matches = [...text.matchAll(/<entry>([\s\S]*?)<\/entry>/g)];

if (!matches.length) {
  return [{ json: { arxiv: '<b>Latest Highlights</b>\n<i>No papers found</i>' } }];
}

const entries = matches
  .map((match) => match[1])
  .map((entry) => {
    const titleMatch = entry.match(/<title>([\s\S]*?)<\/title>/);
    const linkMatch = entry.match(/<id>(https?:\/\/arxiv\.org\/abs\/[^<]+)<\/id>/);
    const summaryMatch = entry.match(/<summary>([\s\S]*?)<\/summary>/);

    if (!titleMatch || !linkMatch) return null;

    return {
      title: clean(titleMatch[1]),
      link: clean(linkMatch[1]),
      summary: summaryMatch ? clean(summaryMatch[1]).slice(0, 120) + '...' : '',
    };
  })
  .filter(Boolean)
  .slice(0, 10);

if (!entries.length) {
  return [{ json: { arxiv: '<b>Latest Highlights</b>\n<i>No papers found</i>' } }];
}

const lines = ['<b>Latest Highlights</b>'];

for (let i = 0; i < entries.length; i++) {
  const item = entries[i];
  lines.push(`${i + 1}. <b>${item.title}</b>`);
  if (item.summary) lines.push(`   ${item.summary}`);
  lines.push(`   🔗 <a href="${item.link}">Read more</a>`);
  lines.push('');
}

return [{ json: { arxiv: lines.join('\n').trim() } }];

const config = $('⚙️ Config').first().json;
if ((config.enableAINews || 'true').toLowerCase() !== 'true' || (config.enableOpenAI || 'true').toLowerCase() !== 'true') {
  return [{ json: { openaiNews: null } }];
}

const items = $input.all();
if (!items.length || !items[0].json?.link || !items[0].json?.title) {
  return [{ json: { openaiNews: null } }];
}

const item = items[0].json;
return [{ json: { openaiNews: `🔔 <b>OpenAI:</b> <a href="${item.link}">${item.title}</a>` } }];

const config = $('⚙️ Config').first().json;
if ((config.enableNotion || 'true').toLowerCase() !== 'true') {
  return [{ json: { tasks: null } }];
}

const pages = $input.all();
if (!pages.length || !pages[0].json?.properties) {
  return [{ json: { tasks: null } }];
}

const getStatusName = (props) => props?.Status?.status?.name || props?.Status?.select?.name || props?.State?.status?.name || '';
const tasks = pages
  .map((p) => {
    const props = p.json.properties || {};
    const status = getStatusName(props).toLowerCase();
    if (status === 'done' || status === 'completed') return null;
    const name = props?.Name?.title?.[0]?.plain_text || props?.Task?.title?.[0]?.plain_text || 'Untitled';
    const project = props?.Project?.select?.name || props?.Project?.multi_select?.[0]?.name || '';
    return project ? `• ${name} — <i>${project}</i>` : `• ${name}`;
  })
  .filter(Boolean)
  .slice(0, 8);

if (!tasks.length) {
  return [{ json: { tasks: '📋 <b>Your Tasks</b>\n<i>No open tasks found</i>' } }];
}

return [{ json: { tasks: ['📋 <b>Your Tasks</b>', ...tasks].join('\n') } }];

const config = $('⚙️ Config').first().json;
if ((config.enableCalendar || 'true').toLowerCase() !== 'true') {
  return [{ json: { calendar: null } }];
}

const raw = $input.first()?.json || {};
const text = raw.data || raw.body || raw.rawBody || Object.values(raw).find((value) => typeof value === 'string') || '';
if (!text || typeof text !== 'string') {
  return [{ json: { calendar: null } }];
}

const timezone = config.timezone || 'Asia/Kolkata';
const parts = new Intl.DateTimeFormat('en-CA', {
  timeZone: timezone,
  year: 'numeric',
  month: '2-digit',
  day: '2-digit'
}).formatToParts(new Date());
const current = Object.fromEntries(parts.map((part) => [part.type, part.value]));
const todayStr = `${current.year}${current.month}${current.day}`;

const events = [];
const eventBlocks = text.match(/BEGIN:VEVENT[\s\S]*?END:VEVENT/g) || [];
for (const block of eventBlocks) {
  const dtstart = block.match(/DTSTART[^:]*:(\d{8}(T\d{4,6}Z?)?)/)?.[1];
  const summary = block.match(/SUMMARY:(.+)/)?.[1]?.trim();
  const location = block.match(/LOCATION:(.+)/)?.[1]?.trim();
  if (!dtstart || !summary) continue;
  if (!dtstart.startsWith(todayStr)) continue;

  let time = 'All day';
  const compact = dtstart.replace(/[^0-9]/g, '');
  if (compact.length >= 12) {
    const hour = compact.slice(8, 10);
    const min = compact.slice(10, 12);
    time = `${hour}:${min}`;
  }

  events.push({ time, summary, location });
}

const normalize = (value) => (value === 'All day' ? '00:00' : value);
events.sort((a, b) => normalize(a.time).localeCompare(normalize(b.time)));

if (!events.length) {
  return [{ json: { calendar: '📅 <b>Today\'s Events</b>\n<i>No events today</i>' } }];
}

const lines = events.map((e) => `• ${e.time} — ${e.summary}${e.location ? ` @ ${e.location}` : ''}`);
return [{ json: { calendar: ['📅 <b>Today\'s Events</b>', ...lines].join('\n') } }];

const config = $('⚙️ Config').first().json;
if ((config.profile || 'student').toLowerCase() !== 'student' || (config.enableTimetable || 'true').toLowerCase() !== 'true') {
  return [{ json: { timetable: null } }];
}

const timezone = config.timezone || 'Asia/Kolkata';
const weekday = new Intl.DateTimeFormat('en-US', { weekday: 'long', timeZone: timezone }).format(new Date());
const timetable = {
  Monday: [
    '09:00 - Operating Systems',
    '11:00 - Machine Learning',
    '14:00 - DBMS Lab'
  ],
  Tuesday: [
    '10:00 - Computer Networks',
    '13:00 - Deep Learning Seminar'
  ],
  Wednesday: [
    '09:30 - Algorithms',
    '12:00 - Project Work'
  ],
  Thursday: [
    '10:00 - Software Engineering',
    '15:00 - Placement Prep'
  ],
  Friday: [
    '08:30 - Revision Block',
    '11:00 - Research Reading',
    '14:00 - Lab / Assignments'
  ],
  Saturday: [
    '10:00 - Personal Study'
  ],
  Sunday: []
};

const entries = timetable[weekday] || [];
if (!entries.length) {
  return [{ json: { timetable: '🗓 <b>Today\'s Timetable</b>\n<i>No classes scheduled</i>' } }];
}

return [{ json: { timetable: ['🗓 <b>Today\'s Timetable</b>', ...entries.map((item) => `• ${item}`)].join('\n') } }];

const config = $('⚙️ Config').first().json;
const all = $input.all().map((item) => item.json || {});

const get = (key) => {
  for (const item of all) {
    if (item[key]) return item[key];
  }
  return null;
};

const divider = '━━━━━━━━━━━━━━━━━━━━━━';
const timezone = config.timezone || 'Asia/Kolkata';
const firstName = config.firstName || 'there';

const dateStr = new Intl.DateTimeFormat('en-US', {
  weekday: 'long',
  day: 'numeric',
  month: 'short',
  year: 'numeric',
  timeZone: timezone,
}).format(new Date());

const quotes = [
  { text: 'The best way to predict the future is to invent it.', author: 'Alan Kay' },
  { text: 'Simplicity is the ultimate sophistication.', author: 'Leonardo da Vinci' },
  { text: 'Done is better than perfect.', author: 'Sheryl Sandberg' },
  { text: 'What we know is a drop, what we do not know is an ocean.', author: 'Isaac Newton' },
  { text: 'Small steps every day.', author: 'Unknown' },
];

const quote = quotes[Math.floor(Math.random() * quotes.length)];

const sections = [];

// Greeting
sections.push(`☀️ <b>Good morning, ${firstName}!</b>\n<i>${dateStr}</i>`);

// Daily essentials
if (get('weather')) sections.push(get('weather'));
if (get('calendar')) sections.push(get('calendar'));
if (get('timetable')) sections.push(get('timetable'));
if (get('tasks')) sections.push(get('tasks'));

// News first
if (get('techNews')) sections.push(get('techNews'));

// AI block after news
const aiItems = [get('arxiv'), get('openaiNews'), get('anthropicNews')].filter(Boolean);
if (aiItems.length) {
  sections.push(['🤖 <b>AI & ML</b>', ...aiItems].join('\n\n'));
}

// Quote last
sections.push(`💡 <i>"${quote.text}"</i>\n${quote.author}`);

const message = sections.join(`\n\n${divider}\n\n`);

const parts = [];
let current = '';

for (const line of message.split('\n')) {
  const next = current ? `${current}\n${line}` : line;

  if (next.length > 4000) {
    if (current) parts.push(current);
    current = line;
  } else {
    current = next;
  }
}

if (current) parts.push(current);

return parts.map((part) => ({
  json: { message: part }
}));
